#include <bits/stdc++.h>
using namespace std;
const int N=1e6+6;
struct Node{
	int p,len;
};
int n,a[N],tot,id[N],f[N],c[N],siz[N];
vector<int> t[N],g[N];
void build(int x,int fa){
	if(fa && a[x]==a[fa])
		id[x]=id[fa];
	else{
		id[x]=++tot,c[tot]=a[x],f[tot]=id[fa];
		if(f[tot])
			g[id[fa]].push_back(id[x]),g[id[x]].push_back(id[fa]);
	}
	int len=t[x].size();
	for(int i=0;i<len;i++)
		if(t[x][i]!=fa)
			build(t[x][i],x);
}
void dfs1(int x,int last){
	int len=g[x].size();
	siz[x]=c[x];
	for(int i=0;i<len;i++){
		if(g[x][i]==last)
			continue;
		dfs1(g[x][i],x);
		siz[x]+=siz[g[x][i]];
	}
}
Node dfs(int x,int last){
	int len=g[x].size(),mx=0,p=x;
	for(int i=0;i<len;i++)
		if(siz[g[x][i]] && g[x][i]!=last){
			Node tmp=dfs(g[x][i],x);
			if(tmp.len+1>mx)
				mx=tmp.len+1,p=tmp.p;
		}
	return {p,mx};
}
int main(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
		scanf("%d",&a[i]);
	for(int i=1;i<n;i++){
		int u,v;
		scanf("%d%d",&u,&v);
		t[u].push_back(v);
		t[v].push_back(u);
	}
	build(1,0);
	if(tot==1 && c[1]==0)
		printf("0");
	else{
		dfs1(1,0);
		printf("%d",(dfs(dfs(1,0).p,0).len+2)/2);
	}
	return 0;
}
